SELECT ?player ?spikeHeight ?positionLabel WHERE { 
?player wdt:P54 wd:Q2617479; 
wdt:P27 wd:Q155; 
wdt:P1344 wd:Q211124; 
wdt:P641 wd:Q3401255; 
wdt:P2551 ?spikeHeight; 
wdt:P413 ?position . 
?position rdfs:label ?positionLabel . 
FILTER (LANG(?positionLabel) = "en") 
} 
ORDER BY ?spikeHeight 
LIMIT 1

