SELECT ?player ?spikeNum ?positionLabel WHERE {
  ?player wdt:P54 wd:Q2617479; 
        wdt:P27 wd:Q155; 
        wdt:P1344 wd:Q19802414; 
        p:P2551/psv:P2551 ?spikeValue;
        wdt:P413 ?position .
  ?spikeValue wikibase:quantityAmount ?spikeNum .
  ?position rdfs:label ?positionLabel .
  FILTER(LANG(?positionLabel) = "en")
}
ORDER BY ASC(?spikeNum)
